import functools

def validator(validate_func, error_message="Validation failed!"):
    """
    Özel bir doğrulayıcı dekoratör oluşturur.

    Args:
        validate_func (callable): Dekore edilen fonksiyonla aynı argümanları alan
                                  ve geçerli veri için True, aksi halde False döndüren bir fonksiyon.
        error_message (str): Doğrulama başarısız olduğunda ValueError ile yükseltilecek mesaj.

    Returns:
        callable: Bir fonksiyona uygulanacak asıl dekoratör.
    """
    def decorate(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            if not validate_func(*args, **kwargs):
                raise ValueError(error_message)
            return func(*args, **kwargs)
        return wrapper
    return decorate

# Kullanım örneği:

# 1. Pozitif sayı kontrolü yapan bir doğrulayıcı fonksiyon
def is_positive(value):
    return value > 0

@validator(is_positive, error_message="Değer pozitif olmalıdır!")
def process_data(number):
    return f"Veri başarıyla işlendi: {number}"

# 2. Birden fazla argümanı doğrulayan bir örnek
def validate_credentials(username, password):
    return len(username) >= 5 and len(password) >= 8 and "!" in password

@validator(validate_credentials, error_message="Geçersiz kullanıcı adı (min 5 karakter) veya şifre (min 8 karakter ve ! içermeli)!")
def create_user(username, password):
    return f"Kullanıcı '{username}' başarıyla oluşturuldu."

# 3. Lambda fonksiyonu ile inline doğrulama
@validator(lambda x, y: x + y < 100, error_message="Toplam 100'den küçük olmalı!")
def calculate_sum(x, y):
    return x + y

